+// validateResourceQuotaRequestVsLimit ensures that for each resource type,
+// if both requests and limits are specified, requests do not exceed limits.
+func validateResourceQuotaRequestVsLimit(hard core.ResourceList, fldPath *field.Path) field.ErrorList {
+	allErrs := field.ErrorList{}
+
+	requestToLimit := map[core.ResourceName]core.ResourceName{
+		core.ResourceRequestsCPU:              core.ResourceLimitsCPU,
+		core.ResourceRequestsMemory:           core.ResourceLimitsMemory,
+		core.ResourceRequestsEphemeralStorage: core.ResourceLimitsEphemeralStorage,
+	}
+
+	for reqResource, limResource := range requestToLimit {
+		reqQuantity, reqFound := hard[reqResource]
+		limQuantity, limFound := hard[limResource]
+		if reqFound && limFound && reqQuantity.Cmp(limQuantity) > 0 {
+			allErrs = append(allErrs, field.Invalid(fldPath.Key(string(reqResource)), reqQuantity.String(),
+				fmt.Sprintf("must be less than or equal to %s limit %s", limResource, limQuantity.String())))
+		}
+	}
+
+	return allErrs
+}
