@@ -533,6 +533,22 @@ func (config *DirectClientConfig) getAuthInfo() (clientcmdapi.AuthInfo, error) {
 		if err := merge(mergedAuthInfo, &config.overrides.AuthInfo); err != nil {
 			return clientcmdapi.AuthInfo{}, err
 		}
+
+		// An override of --client-certificate should clear in-line cert data, and vice versa.
+		// Otherwise, merging file and data results in a validation error.
+		if len(config.overrides.AuthInfo.ClientCertificate) > 0 {
+			mergedAuthInfo.ClientCertificateData = nil
+		}
