+			mergedAuthInfo.ClientCertificate = ""
+		}
+		// An override of --client-key should clear in-line key data, and vice versa.
+		if len(config.overrides.AuthInfo.ClientKey) > 0 {
+			mergedAuthInfo.ClientKeyData = nil
+		}
+		if len(config.overrides.AuthInfo.ClientKeyData) > 0 {
+			mergedAuthInfo.ClientKey = ""
+		}
 	}

 	return *mergedAuthInfo, nil

