+// ensureURLHasScheme ensures that the given URL has a scheme.
+// This is necessary because CONNECT requests may not include a scheme,
+// and httpproxy.Config.ProxyFunc() requires one to resolve proxy settings.
+func ensureURLHasScheme(u *url.URL) *url.URL {
+	if u == nil {
+		return u
+	}
+	if u.Scheme == "" {
+		clone := *u
+		clone.Scheme = "https"
+		return &clone
+	}
+	return u
+}
